import React from "react";

import html5 from './html5.svg';
import css from './css.svg';
import react from './react.svg';

let project_list = [
    {name: "danlliu.github.io", icons: ["html5", "css", "react"], type: "personal website"}
];

const img_lookup = {
    "html5": html5,
    "css": css,
    "react": react
};

const alt_text = {
    "html5": "HTML 5",
    "css": "CSS 3",
    "react": "React.js"
}

class PersonalProjects extends React.Component {

    constructor(props) {
        super(props);
        this.state = {selected: 0};
    }

    render() {
        return (<div>
            <div className={"flexbox wide-scroll"}>
                {project_list.map((x, i) => (<div className={"card"} key={i}>
                    {x.icons.map(y => <img src={img_lookup[y]} title={alt_text[y]} height={36} width={36} style={{margin: 4}} key={y}/>)}
                    <h3 style={{marginBottom: 0}}>{x.name}</h3>
                    <h4 style={{marginBottom: 0}}>{x.type}</h4>
                </div>))}
            </div>
        </div>);
    }

}

export default PersonalProjects;
